heading.css:
font-family: var(--heading-font-family);
  font-weight: var(--heading-font-weight);
  line-height: 1.2;
  color: var(--text-dark);

headline.css:
font-family: var(--heading-font-family);
  font-weight: var(--heading-font-weight);
  line-height: 1.3;
  color: var(--text-dark);

eyebrow.css:
font-size: var(--text-s);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--primary);

lede.css:
font-size: var(--text-l);
  line-height: 1.6;
  color: var(--text-dark-muted);
  max-width: 65ch;

caption.css:
font-size: var(--text-s);
  color: var(--text-dark-muted);
  margin-block-start: var(--space-xs);

blockquote-text.css:
font-size: var(--text-l);
  font-style: italic;
  line-height: 1.6;
  color: var(--text-dark);

citation.css:
font-size: var(--text-s);
  font-style: normal;
  color: var(--text-dark-muted);

intro.css:
display: flex;
  flex-direction: column;
  gap: var(--space-s);

content-wrapper.css:
display: flex;
  flex-direction: column;
  gap: var(--content-gap);

media-wrapper.css:
display: flex;
  overflow: hidden;
  border-radius: var(--radius);

card.css:
display: flex;
  flex-direction: column;
  gap: var(--card-gap, var(--space-m));
  padding: var(--card-padding, var(--space-l));
  border-radius: var(--radius);
  background: var(--white);
  border: 1px solid var(--border);

card-body.css:
display: flex;
  flex-direction: column;
  gap: var(--space-s);

card-header.css:
display: flex;
  flex-direction: column;
  gap: var(--space-xs);

card-footer.css:
display: flex;
  align-items: center;
  gap: var(--space-s);
  margin-block-start: auto;

cta-group.css:
display: flex;
  flex-wrap: wrap;
  gap: var(--space-s);
  align-items: center;

list.css:
display: flex;
  flex-direction: column;
  gap: var(--space-s);
  list-style: none;
  padding: 0;
  margin: 0;

list-item.css:
display: flex;
  align-items: flex-start;
  gap: var(--space-xs);

overlay.css:
:has(> &) { position: relative; isolation: isolate; }
  position: absolute;
  inset: 0;
  z-index: -1;
  pointer-events: none;

button.css:
display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5em;
  cursor: pointer;
  text-decoration: none;
  border: none;
  transition: all var(--transition);

link.css:
color: var(--primary);
  text-decoration: underline;
  text-underline-offset: 0.2em;
  transition: color var(--transition);
  &:hover { color: var(--primary-dark, var(--primary)); }

badge.css:
display: inline-flex;
  align-items: center;
  padding: var(--space-xxs) var(--space-xs);
  font-size: var(--text-s);
  font-weight: 600;
  border-radius: 100vw;
  background: var(--neutral-ultra-light);
  color: var(--text-dark);

tag.css:
display: inline-flex;
  align-items: center;
  padding: var(--space-xxs) var(--space-xs);
  font-size: var(--text-s);
  border-radius: var(--radius);
  background: var(--neutral-ultra-light);
  color: var(--text-dark);

nav-link.css:
color: var(--text-dark);
  text-decoration: none;
  transition: color var(--transition);
  &:hover { color: var(--primary); }

form-field.css:
display: flex;
  flex-direction: column;
  gap: var(--space-xxs);

input.css:
padding: var(--space-xs) var(--space-s);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  font-size: var(--text-m);
  transition: border-color var(--transition);
  &:focus { border-color: var(--primary); outline: var(--focus-width) solid var(--focus-color); outline-offset: var(--focus-offset); }
